                        <button className={`px-3 py-1 border rounded-lg text-sm transition-colors duration-200 ${
                            isDarkMode 
                                ? 'border-gray-600 text-gray-300 bg-gray-800 hover:bg-gray-700' 
                                : 'border-gray-300 text-gray-700 bg-white hover:bg-gray-50'
